parameters.jsonBody:
={{ {
  "model": "llama-3.1-8b-instant",
  "temperature": 0.7,
  "response_format": { "type": "json_object" },
  "messages": [
    {
      "role": "system",
      "content": "You are an expert direct-response copywriter. Your job is to convert a validated business opportunity into high-converting messaging assets.

RULES:
- Use the exact problem language
- Match tone to ICP
- Avoid generic marketing phrases
- Do NOT sound like AI
- Be specific and concrete

OUTPUT FORMAT (STRICT JSON ONLY):
{
  "core_message": "One clear positioning sentence",
  "angles": [
    { "type": "pain", "message": "Highlight frustration" },
    { "type": "outcome", "message": "Highlight result" },
    { "type": "contrarian", "message": "Challenge common belief" }
  ],
  "assets": {
    "linkedin_post": "3-5 lines, engaging",
    "cold_dm": "Short, direct, personalized tone",
    "email": "Slightly longer, structured"
  }
}"
    },
    {
      "role": "user",
      "content": "Convert the following input into structured messaging assets:

" + $json.prompt_input
    }
  ]
} }}

assignments.value:
={{ 
(() => {
  const content = $json.choices?.[0]?.message?.content;
  if (!content) return { error: 'No response from AI' };

  try {
    return JSON.parse(content);
  } catch (e) {
    return { error: 'Invalid JSON format from AI' };
  }
})()
}}
